const auth = $input.first().json;
if (auth.retornoCodigo !== 0) throw new Error('Falha autenticação: ' + auth.retorno);
return [{ json: { token: auth.token, chave: auth.chave } }];

const form = $('Consultar MTRs Webhook').first().json.body;
const auth = $input.first().json;

// ⚠️ VERIFICAR: confirme o endpoint correto com a FEAM/MTR-MG
// Candidatos: listarManifestos, consultarManifestos, listarManifestosParaReceber
const payload = {
  cnpDestinador: '07711109000186',
  codUnidadeDestinador: 255271,
  dataInicio: form['dataInicio'],
  dataFim: form['dataFim']
};

return [{ json: { payload, token: auth.token, chave: auth.chave } }];

const resp = $input.first().json;

// Erro geral da API
if (resp.retornoCodigo !== undefined && resp.retornoCodigo !== 0) {
  return [{ json: {
    sucesso: false,
    total: 0,
    manifests: [],
    mensagem: `❌ Erro ${resp.retornoCodigo}: ${resp.retorno}`
  }}];
}

// Normaliza: a API pode retornar array direto ou dentro de uma chave
const lista = Array.isArray(resp)
  ? resp
  : (resp.manifestoJSONDtos || resp.manifests || resp.data || []);

const pendentes = lista.filter(m => {
  // Filtra apenas os que ainda não têm baixa (ajuste o campo conforme a API retornar)
  const situacao = m.situacao ?? m.manifSituacao ?? m.status ?? null;
  // null/undefined = assumir pendente; 1 = emitido sem baixa (ajuste se necessário)
  return situacao === null || situacao === undefined || situacao === 1 || situacao === '1';
});

return [{ json: {
  sucesso: true,
  total: lista.length,
  totalPendentes: pendentes.length,
  manifests: lista,
  mensagem: `✅ ${lista.length} MTR(s) encontrado(s), ${pendentes.length} pendente(s) de baixa`
} }];
